import React, { useEffect, useState } from 'react';
import './styles/App.css';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { supabase } from './services/supabaseClient';

// Importação de Componentes e Páginas
import Sidebar from './components/Sidebar';
import Menu from './pages/Menu';
import Lancamento from './pages/Lancamento';
import Listagem from './pages/Listagem';
import Dashboard from './pages/Dashboard';
import Cartoes from './pages/Cartoes';
import Login from './pages/Login';
import Registro from './pages/Registro';
import Perfil from './pages/Perfil'; // <-- Adicionada a importação necessária

function App() {
  const [session, setSession] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Busca a sessão inicial de forma assíncrona
    const getInitialSession = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      setSession(session);
      setLoading(false);
    };

    getInitialSession();

    // Listener para mudanças no estado de autenticação
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setLoading(false); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  // Tela de carregamento
  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        height: '100vh', 
        width: '100vw', 
        alignItems: 'center', 
        justifyContent: 'center', 
        background: '#f8fafc' 
      }}>
        <div className="loader">Carregando...</div>
      </div>
    );
  }

  return (
    <Router>
      <div className="main-wrapper">
        {!session ? (
          /* --- FLUXO PÚBLICO (Deslogado) --- */
          <Routes>
            <Route path="/login" element={<Login />} />
            <Route path="/registro" element={<Registro />} />
            <Route path="*" element={<Navigate to="/login" replace />} />
          </Routes>
        ) : (
          /* --- FLUXO PRIVADO (Logado) --- */
          <div className="app-container">
            <Sidebar />
            <main className="content-area">
              <Routes>
                <Route path="/" element={<Menu />} />
                <Route path="/lancamento" element={<Lancamento />} />
                <Route path="/listagem" element={<Listagem />} />
                <Route path="/dashboard" element={<Dashboard />} />
                <Route path="/cartoes" element={<Cartoes />} />
                <Route path="/perfil" element={<Perfil />} />
                
                {/* Redirecionamentos de segurança para rotas públicas */}
                <Route path="/login" element={<Navigate to="/" replace />} />
                <Route path="/registro" element={<Navigate to="/" replace />} />
                
                {/* Fallback para rotas inexistentes */}
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </main>
          </div>
        )}
      </div>
    </Router>
  );
}

export default App;
